```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // packet_id
        stream.serialise(packet_id);

        // username with length prefix
        uint32_t username_len = static_cast<uint32_t>(username.size());
        stream.serialise(username_len);
        stream.serialise_bytes(
            reinterpret_cast<const std::byte*>(username.data()),
            username_len
        );

        // scores: count + contents (operator<< calls write_container internally)
        uint32_t scores_count = static_cast<uint32_t>(scores.size());
        stream.serialise(scores_count);
        stream << scores;

        // metadata: null-terminated using adaptor
        stream.serialise(hexi::null_terminated(metadata));
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    std::vector<uint8_t> buffer;
    buffer.reserve(128); // optional pre-reserve

    // Wrap the buffer's data pointer with a Hexi output stream.
    // Hexi expects std::byte*, so we use a byte proxy over the vector.
    hexi::vector_sink<std::byte> sink;
    sink.data().reserve(buffer.capacity());

    hexi::ostream out{sink};
    out.serialise(const_cast<NetworkPacket&>(packet)); // serialise uses auto& stream

    // Copy from internal sink storage to the uint8_t buffer
    buffer.resize(sink.data().size());
    for (std::size_t i = 0; i < sink.data().size(); ++i) {
        buffer[i] = static_cast<uint8_t>(sink.data()[i]);
    }

    return buffer;
}
