#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket pkt;

    // Create a reader over the buffer
    hexi::reader r{buffer};

    // 1. Read packet_id
    r.read(pkt.packet_id);

    // 2. Read username using length prefix (uint32_t length + bytes)
    {
        uint32_t name_len{};
        r.read(name_len);
        pkt.username.resize(name_len);
        r.read_raw(pkt.username.data(), name_len);
    }

    // 3. Read the score count, then the scores vector via read_container
    {
        uint32_t score_count{};
        r.read(score_count);
        pkt.scores.resize(score_count);
        r.read_container(pkt.scores);
    }

    // 4. Read metadata string as null-terminated (zero-copy in reader,
    //    but here we materialize into std::string)
    {
        std::string_view meta_view = r.read_cstr();  // reads until '\0'
        pkt.metadata.assign(meta_view.begin(), meta_view.end());
    }

    // 5. Skip any remaining padding bytes (if any)
    if (!r.empty()) {
        r.skip(r.remaining());
    }

    return pkt;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info{};

    hexi::reader r{buffer};

    // 1. Use span() to get zero-copy view of packet_id (first 4 bytes)
    {
        auto id_span = r.span<std::uint32_t>(1);  // span of 1 uint32_t
        info.packet_id = *id_span.data();         // copy value out
    }

    // 2. Read username using prefixed adaptor for a string_view
    {
        // username is stored as [uint32 length][bytes...]
        std::string_view name_view;
        r.read(hexi::prefixed<std::uint32_t>(name_view));
        info.username = name_view;
    }

    // 3. Skip the scores vector without reading each element:
    //    - read count
    //    - skip count * sizeof(uint32_t) bytes
    {
        uint32_t score_count{};
        r.read(score_count);
        std::size_t to_skip = static_cast<std::size_t>(score_count) * sizeof(std::uint32_t);
        r.skip(to_skip);
    }

    return info;
}
