```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

// Get the current read pointer for a Hexi buffer.
// The Hexi API tracks read/write positions; we expose the current read pointer
// as a const uint8_t* into the underlying storage.
const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Wrap the existing storage in a Hexi buffer view. This does not copy data.
    hexi_buffer_view view{
        const_cast<uint8_t*>(buffer.data()),  // Hexi expects non-const data pointer
        buffer.size()
    };

    // Query the current read position and base pointer from Hexi.
    size_t read_pos = hexi_get_read_pos(&view);
    uint8_t* base_ptr = hexi_get_data_ptr(&view);

    // Compute and return a const pointer at the current read position.
    return base_ptr + read_pos;
}

// Get the current write pointer for a Hexi buffer.
// We return a non-const pointer so callers can write into the buffer
// starting at the current write position.
uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    hexi_buffer_view view{
        buffer.data(),
        buffer.size()
    };

    size_t write_pos = hexi_get_write_pos(&view);
    uint8_t* base_ptr = hexi_get_data_ptr(&view);

    return base_ptr + write_pos;
}

struct BufferInfo {
    size_t readable_size;  // bytes between read and write positions
    size_t free_space;     // bytes remaining from write position to end
};

// Check how much data is currently readable and how much free space remains.
BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    hexi_buffer_view view{
        const_cast<uint8_t*>(buffer.data()),
        buffer.size()
    };

    size_t read_pos  = hexi_get_read_pos(&view);
    size_t write_pos = hexi_get_write_pos(&view);
    size_t capacity  = hexi_get_capacity(&view);

    BufferInfo info{};
    info.readable_size = (write_pos >= read_pos) ? (write_pos - read_pos) : 0;
    info.free_space    = (capacity >= write_pos) ? (capacity - write_pos) : 0;

    return info;
}
```

