#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};
    result.data_type = 0;

    // Create a buffer adaptor over the input buffer
    hexi::buffer_adaptor adaptor{
        reinterpret_cast<const char*>(buffer.data()),
        buffer.size()
    };

    // Wrap it in a binary_stream
    hexi::binary_stream stream{adaptor};

    // Preview the first byte (data_type) without advancing the read pointer.
    // Use read_at with offset 0 so the stream's position doesn't change.
    {
        uint8_t preview_type = 0;
        // Ensure we have at least 1 byte for the data_type
        if (stream.size() < sizeof(preview_type)) {
            // Not enough data; return default result
            return result;
        }

        stream.read_at(0, preview_type);
        result.data_type = preview_type;
    }

    // Now actually read from the start in normal sequence
    stream.seek(0, hexi::seek_origin::beg);

    // Check we have at least data_type + item_count
    if (stream.size() < sizeof(uint8_t) + sizeof(uint32_t)) {
        return result; // not enough data
    }

    uint8_t data_type = 0;
    uint32_t item_count = 0;

    stream.read(data_type);
    stream.read(item_count);

    result.data_type = data_type;

    // Calculate required payload size and verify
    std::size_t item_size = (data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    std::size_t required_size =
        sizeof(uint8_t) + sizeof(uint32_t) + static_cast<std::size_t>(item_count) * item_size;

    if (stream.size() < required_size) {
        // Not enough data for all items; return what we have in header
        return result;
    }

    if (data_type == 0) {
        // Integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value = 0;
            stream.read(value);
            result.int_items[i] = value;
        }
    } else if (data_type == 1) {
        // Floats
