```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor over the raw memory
    hexi::buffer_adaptor adaptor{buffer.data(), buffer.size()};

    // Create a binary stream on top of the adaptor
    hexi::binary_stream stream{adaptor};

    MessagePacket packet{};

    // Read the 32-bit header
    packet.header = stream.read<uint32_t>();

    // Remaining bytes should contain a null-terminated string.
    // Get a view over the remaining raw bytes.
    auto remaining = stream.view<std::byte>(stream.remaining());

    const char* begin = reinterpret_cast<const char*>(remaining.data());
    const char* end   = begin + remaining.size();

    // Find the null terminator
    const char* terminator = begin;
    while (terminator != end && *terminator != '\0') {
        ++terminator;
    }

    // Construct a string_view up to (but not including) the null terminator
    packet.message = std::string_view{begin, static_cast<std::size_t>(terminator - begin)};

    return packet;
}
