#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <array>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations.
//
// The idea:
// - Construct a block_allocator with a fixed pool.
// - Perform a sequence of allocate()/deallocate() calls.
// - Print the returned addresses so we can infer the free-list behavior:
//   * allocate() uses pop() to remove from the head of the free list
//   * deallocate() uses push() to insert back at the head of the free list
//
// From this we can see that:
// - The allocator hands out blocks in LIFO order (stack-like behavior).
// - The most recently deallocated block is the next one to be allocated.

template<std::size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // We'll use a simple POD type so the allocator can manage fixed-size blocks.
    struct Node {
        std::uint64_t value;
        std::uint64_t next;
    };

    // Backing storage for the allocator: element_count Node objects.
    // block_allocator will carve this buffer into fixed-size blocks.
    std::array<Node, element_count> storage{};

    // Create a block_allocator that manages blocks of sizeof(Node)
    // out of our pre-allocated storage.
    //
    // Typical Hexi signature is:
    //   hexi::block_allocator(std::size_t block_size, void* buffer, std::size_t buffer_size);
    //
    // If your Hexi version differs, adjust the constructor call accordingly.
    hexi::block_allocator allocator{
        sizeof(Node),
        static_cast<void*>(storage.data()),
        storage.size() * sizeof(Node)
    };

    std::cout << "=== Demonstrating hexi::block_allocator free list behavior ===\n";
    std::cout << "Block size: " << sizeof(Node) << " bytes\n";
    std::cout << "Total elements in pool: " << element_count << "\n\n";

    // 1. Allocate a few blocks and observe their addresses
    constexpr std::size_t first_round = 4;
    Node* ptrs[first_round]{};

    std::cout << "First round of allocations (" << first_round << " blocks):\n";
    for (std::size_t i = 0; i < first_round; ++i) {
        void* raw = allocator.allocate();     // internally calls pop()
        ptrs[i]   = static_cast<Node*>(raw);
        std::cout << "  allocate() -> ptrs[" << i << "] = " << static_cast<void*>(ptrs[i]) << "\n";
    }

    std::cout << "\nAt this point, the allocator has popped " << first_round
              << " blocks from the free list head.\n\n";

    // 2. Deallocate some of them in a particular order
    // We deallocate in the order: 1, 3, 2 (indices), leaving ptrs[0] still allocated.
    std::cout << "Deallocating some blocks in non-sequential order:\n";
    std::cout << "  deallocate(ptrs[1])\n";
    allocator.deallocate(ptrs[1]);           // internally calls push()
    std::cout << "  deallocate(ptrs[3])\n";
    allocator.deallocate(ptrs[3]);           // internally calls push()
    std::cout << "  deallocate(ptrs[2])\n";
    allocator.deallocate(ptrs[2]);           // internally calls push()

    std::cout << "\nBecause deallocate() uses push() (LIFO), the free list head"
                 " after these operations is: ptrs[2] -> ptrs[3] -> ptrs[1] -> ...\n\n";

    // 3. Allocate three more blocks and observe the order.
    // If push/pop are stack-like, we should see ptrs[2], then ptrs[3], then ptrs[1].
    std::cout << "Second round of allocations (3 blocks):\n";
    void* a1 = allocator.allocate();         // expected to be ptrs[2]
    void* a2 = allocator.allocate();         // expected to be ptrs[3]
    void* a3 = allocator.allocate();         // expected to be ptrs[1]

    std::cout << "  allocate() -> a1 = " << a1 << "\n";
    std::cout << "  allocate() -> a2 = " << a2 << "\n";
    std::cout << "  allocate() -> a3 = " << a3 << "\n\n";

    std::cout << "Expected LIFO behavior (due to push/pop on free list):\n"
              << "  a1 == ptrs[2]\n"
              << "  a2 == ptrs[3]\n"
              << "  a3 == ptrs[1]\n\n";

    std::cout << "We can check this directly:\n";
    std::cout << "  (a1 == ptrs[2]) ? " << (a1 == ptrs[2] ? "true" : "false") << "\n";
    std::cout << "  (a2 == ptrs[3]) ? " << (a2 == ptrs[3] ? "true" : "false") << "\n";
    std::cout << "  (a3 == ptrs[1]) ? " << (a3 == ptrs[1] ? "true" : "false") << "\n\n";

    std::cout << "This demonstrates how the internal free list behaves:\n"
              << "  - deallocate() pushes the block to the head of the free list.\n"
              << "  - allocate() pops from that head, giving a last-deallocated, first-reallocated order.\n\n";

    // Clean up remaining allocations so we don't leak from the pool in longer-lived programs.
    // Still allocated: ptrs[0], plus the three from the second round (a1/a2/a3).
    std::cout << "Cleaning up remaining allocations...\n";
    allocator.deallocate(ptrs[0]);
    allocator.deallocate(a1);
    allocator.deallocate(a2);
    allocator.deallocate(a3);

    std::cout << "=== End of demonstration ===\n";
}
```

