#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    // Treat the stored bytes as big-endian, convert to native in-place.
    // Hexi provides hexi::endian_swap_inplace which swaps the byte order.
    // We only need to swap when the native endianness is little.
    if constexpr (std::endian::native == std::endian::little) {
        hexi::endian_swap_inplace(value);
    }
    // If native is big-endian, nothing to do.
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    // Treat the stored bytes as little-endian, convert to native in-place.
    // Swap only when the native endianness is big.
    if constexpr (std::endian::native == std::endian::big) {
        hexi::endian_swap_inplace(value);
    }
    // If native is little-endian, nothing to do.
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    // Generic in-place conversion between two explicit endianness formats.
    // If they differ, swapping bytes converts from one to the other.
    if constexpr (from != to) {
        hexi::endian_swap_inplace(value);
    }
    // If from == to, nothing to do.
}
