```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    size_t bytes_to_preview
) {
    std::vector<uint8_t> result;

    // Number of bytes currently readable
    const auto available = storage.readable_size();
    if (available == 0 || bytes_to_preview == 0) {
        return result;
    }

    const auto to_copy = std::min(available, bytes_to_preview);
    result.resize(to_copy);

    // Non-const access for reading; this does NOT advance the read offset.
    uint8_t* dst = result.data();
    size_t remaining = to_copy;

    // intrusive_storage provides segmented access via contiguous_read()
    // without advancing the internal read pointer.
    //
    // We iterate over the readable segments and copy out up to `to_copy`
    // bytes, never calling the API that advances the read offset.
    auto pos = storage.read_pos();
    while (remaining > 0) {
        const uint8_t* segment_ptr = nullptr;
        size_t segment_len = 0;

        // Get the next contiguous readable region from current position
        if (!storage.contiguous_read(pos, segment_ptr, segment_len) ||
            segment_len == 0) {
            break;
        }

        const size_t chunk = std::min(segment_len, remaining);
        std::copy_n(segment_ptr, chunk, dst);

        dst       += chunk;
        remaining -= chunk;
        pos       += chunk;
    }

    // In case contiguous_read returned less than expected for any reason
    result.resize(to_copy - remaining);
    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;
    status.readable_size = storage.readable_size();

    // Assuming intrusive_storage exposes capacity() and writable_size()
    // or equivalent. If only capacity() is available, free space is:
    //
    //   capacity() - readable_size;
    //
    // Prefer a dedicated writable_size() if it exists.
#ifdef HEXI_INTRUSIVE_STORAGE_HAS_WRITABLE_SIZE
    status.free_space = storage.writable_size();
#else
    status.free_space = storage.capacity() - status.readable_size;
#endif

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // intrusive_storage commonly exposes a clear()/reset() that
    // resets both read and write offsets and keeps allocated memory.
#ifdef HEXI_INTRUSIVE_STORAGE_HAS_RESET
    storage.reset();
#else
    storage.clear();
#endif
}
