std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer fb(file_path, hexi::file_buffer::mode::read);

    const auto available = fb.size();
    const auto to_read   = std::min(bytes_to_read, available);

    std::vector<uint8_t> buffer(to_read);
    if (to_read > 0) {
