std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open the file buffer
    hexi::file_buffer fb(file_path);

    // Determine how many bytes we can actually preview
    const auto file_size = fb.size();
    const auto bytes_to_read = static_cast<size_t>(
        std::min<std::uintmax_t>(file_size, static_cast<std::uintmax_t>(header_size))
    );

    std::vector<uint8_t> header(bytes_to_read);

    // Save current read position
    const auto original_pos = fb.tell();

    // Read header bytes starting from the beginning (or current position if desired)
    fb.seek(0, hexi::seek_origin::begin);
    fb.peek(header.data(), bytes_to_read);  // Hexi's non-advancing read

    // Restore original read position
    fb.seek(original_pos, hexi::seek_origin::begin);

    return header;
}
