#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer,
                                         size_t bytes_to_preview) {
    // Clamp preview size to the number of bytes actually available to read
    const auto available = buffer.readable_size();
    if (bytes_to_preview > available) {
        bytes_to_preview = available;
    }

    std::vector<uint8_t> result(bytes_to_preview);

    // Use a read context/guard if Hexi provides one, otherwise manually restore
    // the read position after a temporary read.
    const auto original_read_pos = buffer.read_pos();

    // Read into a temporary buffer but then restore the read position so that
    // the caller's view of the buffer is unchanged.
    if (bytes_to_preview > 0) {
        // Hexi's static_buffer works with std::byte, so we must use a temporary
        // buffer of std::byte and then convert to uint8_t.
        std::vector<std::byte> temp(bytes_to_preview);
        buffer.read(temp.data(), bytes_to_preview);

        // Convert std::byte to uint8_t for the output vector
        for (size_t i = 0; i < bytes_to_preview; ++i) {
            result[i] = static_cast<uint8_t>(temp[i]);
        }

        // Restore the read position so the buffer is not advanced
        buffer.set_read_pos(original_read_pos);
    }

    return result;
}
