#include <vector>
#include <cstdint>
#include <cstring>  // for std::memcmp

// Copy 'length' bytes from the buffer into 'data' without advancing
// the buffer's read pointer.
void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           void* data, std::size_t length) {
    // Use the non-template overload of copy() that takes (void*, size_t, bool)
    // The last argument 'false' means "do not advance the read pointer".
    buffer.copy(data, length, false);
}

template<typename T>
