bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // The buffer_adaptor exposes capability flags via can_write_seek().
    // Return true if write seeking is supported, false otherwise.
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                         hexi::buffer_seek direction,
                         std::size_t offset) {
    // Use the buffer_adaptor's write_seek API.
    // The semantics of offset depend on the direction:
    //  - buffer_seek::begin:  offset is an absolute position from the start.
    //  - buffer_seek::current: offset is relative to the current write position.
    //  - buffer_seek::end:    offset is relative to the end.
    //
    // We simply forward the call; the adaptor is responsible for bounds checking.
    buffer.write_seek(direction, static_cast<std::ptrdiff_t>(offset));
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                               uint32_t header_value) {
    // We want to:
    //  1) Remember the current write position.
    //  2) Write a placeholder header at the beginning of the buffer.
    //  3) Seek back to the original position and write the body (user code outside this function).
    //  4) Later, seek back to the beginning to update the header with header_value.
    //
    // This example implements a self‑contained pattern:
    //  - Save current position.
    //  - Seek to beginning and write placeholder header.
    //  - Seek back to original position (simulating writing body).
    //  - Seek again to beginning to update header with header_value.
    //
    // In a real scenario, you might split this into two calls:
    //  one to write the placeholder and remember the position,
    //  another to update the header after body is written.

    if (!buffer.can_write_seek()) {
        // If write seeking isn't supported, we can't perform the requested operation.
        return;
    }

    // 1) Save current write position
    auto current_pos = buffer.write_tell();

    // 2) Seek to beginning and write a placeholder header (e.g., 0)
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    uint32_t placeholder = 0;
    std::byte header_bytes[sizeof(uint32_t)];
    std::memcpy(header_bytes, &placeholder, sizeof(uint32_t));
    buffer.write(header_bytes, sizeof(uint32_t));

    // 3) Seek back to the original position where body writing continues
    buffer.write_seek(hexi::buffer_seek::begin,
                      static_cast<std::ptrdiff_t>(current_pos));

    // At this point, user code would typically write the body to the buffer.
    // For this function, we assume the body has already been written, and
    // we just need to update the header with 'header_value'.

    // 4) Seek back to the beginning to overwrite the header with the new value
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    std::memcpy(header_bytes, &header_value, sizeof(uint32_t));
    buffer.write(header_bytes, sizeof(uint32_t));

    // Optionally, restore the write position to where it was after body writing.
    // Here we restore to the end of the buffer, assuming that after updating
    // the header, further writing continues at the end.
    buffer.write_seek(hexi::buffer_seek::end, 0);
