#include <type_traits>

using namespace hexi::detail;

// Helper: ZigZag encode for signed integers
template<typename T>
typename std::make_unsigned<T>::type zigzag_encode(T value) {
    using Unsigned = typename std::make_unsigned<T>::type;
    // Shift left by 1 and xor with sign bit shifted to LSB
    return (static_cast<Unsigned>(value) << 1) ^
           static_cast<Unsigned>(value >> (sizeof(T) * 8 - 1));
}

// Helper: ZigZag decode for signed integers
template<typename T>
T zigzag_decode(typename std::make_unsigned<T>::type uvalue) {
    using Unsigned = typename std::make_unsigned<T>::type;
    return static_cast<T>((uvalue >> 1) ^ static_cast<Unsigned>(-static_cast<Unsigned>(uvalue & 1)));
}

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    static_assert(std::is_integral<T>::value, "encode_varint requires an integral type");

    using Unsigned = typename std::make_unsigned<T>::type;
    Unsigned uvalue;

    if constexpr (std::is_signed<T>::value) {
        uvalue = zigzag_encode(value);
    } else {
        uvalue = static_cast<Unsigned>(value);
    }

    std::size_t bytes_written = 0;
    while (true) {
        std::uint8_t byte = static_cast<std::uint8_t>(uvalue & 0x7F);
        uvalue >>= 7;
        if (uvalue != 0) {
            byte |= 0x80; // set continuation bit
        }
        writer.write(byte);
        ++bytes_written;
        if (uvalue == 0) {
            break;
        }
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    static_assert(std::is_integral<T>::value, "decode_varint requires an integral type");

    using Unsigned = typename std::make_unsigned<T>::type;
    Unsigned result = 0;
    std::size_t shift = 0;

    while (true) {
        std::uint8_t byte = 0;
        reader.read(byte);

        Unsigned part = static_cast<Unsigned>(byte & 0x7F);
        result |= (part << shift);

        if ((byte & 0x80) == 0) {
            break; // last byte
        }

        shift += 7;

        // Safety: prevent overflow if malformed varint is too long
        if (shift >= sizeof(Unsigned) * 8 + 7) {
            // For production code, you might throw or signal an error
            break;
        }
    }

    if constexpr (std::is_signed<T>::value) {
        return zigzag_decode<T>(result);
    } else {
        return static_cast<T>(result);
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    static_assert(std::is_integral<T>::value, "encode_decode_roundtrip requires an integral type");

    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream_writer writer(adaptor);

