#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len,
                           const void* dst, std::size_t dst_len) {
    // Treat empty regions as non-overlapping
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    // Convert to byte pointers for arithmetic
    auto src_begin = static_cast<const std::byte*>(src);
    auto dst_begin = static_cast<const std::byte*>(dst);

    // Use Hexi's add_offset to avoid undefined behavior and overflow
    const std::byte* src_end = add_offset(src_begin, src_len);
    const std::byte* dst_end = add_offset(dst_begin, dst_len);

    // Two half-open intervals [src_begin, src_end) and [dst_begin, dst_end)
    // overlap if each starts before the other ends.
    return (src_begin < dst_end) && (dst_begin < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Zero-length copy is always safe and becomes a no-op
    if (length == 0) {
        return true;
    }

    // Check for overlap between source and destination regions
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // Overlap detected; do not perform the copy
    }

    // Safe to copy
    std::memcpy(destination, source, length);
    return true;
}
