    // In a real scenario, you might choose a fixed capacity and check for
    // truncation; here we'll simply size it to input_data.size().
    std::vector<uint8_t> backing_buffer(input_data.size());

    // Create a write adaptor over the backing buffer.
    hexi::pmc::buffer_write_adaptor writer(backing_buffer.data(),
                                           backing_buffer.size());

    // Write as much as possible from input_data into the buffer,
    // checking available space with free().
    std::size_t total_written = 0;
    while (total_written < input_data.size() && writer.free() > 0) {
        std::size_t to_write =
            std::min<std::size_t>(writer.free(), input_data.size() - total_written);
        std::size_t written = writer.write(
            input_data.data() + total_written,
            to_write
        );
        if (written == 0) {
            // No progress; stop to avoid an infinite loop.
            break;
        }
        total_written += written;
    }

    // Now create a read adaptor over the same backing buffer.
    hexi::pmc::buffer_read_adaptor reader(backing_buffer.data(),
                                          backing_buffer.size());

    // Read back only the portion we successfully wrote.
    std::vector<uint8_t> output(total_written);
    std::size_t total_read = 0;

    while (total_read < total_written && reader.size() > 0) {
        std::size_t to_read =
            std::min<std::size_t>(reader.size(), total_written - total_read);
        std::size_t read_bytes = reader.read(
            output.data() + total_read,
            to_read
        );
        if (read_bytes == 0) {
            // No progress; stop to avoid an infinite loop.
            break;
        }
        total_read += read_bytes;
    }

    // If, for some reason, we read less than written, shrink result.
    if (total_read < output.size()) {
        output.resize(total_read);
    }

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data,
                                                 std::size_t peek_size) {
    // Create a read adaptor over the provided buffer data.
    hexi::pmc::buffer_read_adaptor reader(
        const_cast<uint8_t*>(buffer_data.data()), // adaptor likely needs non-const
        buffer_data.size()
    );

    // Determine how many bytes we can actually peek.
    std::size_t available = reader.size();
    std::size_t to_peek = std::min<std::size_t>(peek_size, available);

    // Use copy() to peek data without advancing the read cursor.
    std::vector<uint8_t> peeked(to_peek);
    if (to_peek > 0) {
        reader.copy(peeked.data(), to_peek);
    }

    // We can also inspect the current read pointer without advancing.
    // (Not strictly required for the return value, but demonstrates read_ptr().)
    const uint8_t* current_read_ptr = reader.read_ptr();
    (void)current_read_ptr; // suppress unused variable warning if not used

    // Now actually consume the same amount of data we just peeked using read().
    if (to_peek > 0) {
        std::vector<uint8_t> consumed(to_peek);
        reader.read(consumed.data(), to_peek);
        // 'consumed' should be identical to 'peeked' if the buffer hasn't changed.
    }

    // Return the data that was peeked (not the consumed copy).
    return peeked;
}

