    // Write the container (already big-endian)
    stream.write_container(be_values);

    // Convert and write checksum
    uint32_t be_checksum = native_to_big(packet.checksum);
    stream.write(be_checksum);

    // Extract the underlying buffer
    auto buffer_span = stream.buffer(); // assuming Hexi provides this
    return std::vector<uint8_t>(buffer_span.begin(), buffer_span.end());
