struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Serialisation (writing)
    void serialise(auto& adaptor) const {
        // Write sensor_id directly (assume protocol is native-endian for this field)
        adaptor.serialise(sensor_id);

        // Write number of temperature samples so we can read them back
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor.serialise(count);

        // Convert each temperature from native to little-endian and write
        for (float t : temperatures) {
            float le_t = hexi::endian::conditional_reverse(
                t,
                std::endian::native,
                std::endian::little
            );
            adaptor.write(le_t);
        }

        // Convert pressure from native to little-endian and write
        double le_p = hexi::endian::conditional_reverse(
            pressure,
            std::endian::native,
            std::endian::little
        );
        adaptor.write(le_p);
    }

    // Deserialisation (reading)
    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.serialise(sensor_id);

        // Read number of temperature samples
        uint32_t count = 0;
        adaptor.serialise(count);
        temperatures.resize(count);

        // Read temperatures, then convert in-place from little-endian to native
        for (auto& t : temperatures) {
            adaptor.read(t);
            hexi::endian::little_to_native_inplace(t);
        }

        // Read pressure, then convert in-place from little-endian to native
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

